+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			result := isPIDAlive(tt.pid)
+			if result != tt.expected {
+				t.Errorf("isPIDAlive(%d) = %v, want %v (%s)",
+					tt.pid, result, tt.expected, tt.description)
+			}
+		})
+	}
+}
